1	package com.meridian.retail.security;
2	
3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.stereotype.Component;
10	import org.springframework.web.filter.OncePerRequestFilter;
11	import org.springframework.web.util.ContentCachingRequestWrapper;
12	
13	import javax.crypto.Mac;
14	import javax.crypto.spec.SecretKeySpec;
15	import java.io.IOException;
16	import java.nio.charset.StandardCharsets;
17	import java.security.MessageDigest;
18	import java.util.HexFormat;
19	
20	/**
21	 * HMAC-SHA256 request-signing filter for privileged endpoints.
22	 *
23	 * Applies to: POST /admin/**.
24	 *
25	 * Two canonical-string modes are accepted:
26	 *
27	 *   1. Header mode (programmatic / JSON / multipart callers).
28	 *      Header X-Signature carries the hex HMAC-SHA256 of:
29	 *          HTTP_METHOD + "\n" + REQUEST_PATH + "\n" + X-Timestamp + "\n" + SHA256(body, hex)
30	 *
31	 *   2. Form mode (browser POSTs enriched by static/js/nonce-form.js).
32	 *      Form parameter _signature carries the hex HMAC-SHA256 of:
33	 *          HTTP_METHOD + "\n" + REQUEST_PATH + "\n" + _timestamp + "\n" + _nonce
34	 *      The body hash is intentionally omitted in form mode because the body itself
35	 *      contains the _signature parameter (chicken-and-egg). Replay protection comes
36	 *      from the single-use nonce — see {@link NonceValidationFilter} which runs before
37	 *      this filter and consumes the nonce. Browser-side computation of HMAC is avoided
38	 *      by routing the JS through {@code RequestSigningService.sign(...)} via
39	 *      {@code POST /admin/sign-form} (and {@code /approval/sign-form}), which performs
40	 *      the signing server-side using the same secret.
41	 *
42	 * R4 audit HIGH #2 fix: the previous {@code application/x-www-form-urlencoded} bypass
43	 * for /admin/** is removed. Browser form POSTs flow through this filter and must carry
44	 * a valid {@code _signature} form parameter or be rejected.
45	 *
46	 * The HMAC key is the value of {@code app.signing.secret} in application.yml — hardcoded
47	 * locally so QA can build and run with zero configuration. In a real production deployment
48	 * this would be sourced from a secret manager.
49	 *
50	 * Wrapping the request with {@link ContentCachingRequestWrapper} lets us read the body for
51	 * hashing without consuming it from the downstream chain.
52	 */
53	@Component
54	@Slf4j
55	public class RequestSigningFilter extends OncePerRequestFilter {
56	
57	    @Value("${app.signing.secret}")
58	    private String signingSecret;
59	
60	    @Override
61	    protected void doFilterInternal(HttpServletRequest request,
62	                                    HttpServletResponse response,
63	                                    FilterChain chain) throws ServletException, IOException {
64	
65	        if (!appliesTo(request)) {
66	            chain.doFilter(request, response);
67	            return;
68	        }
69	
70	        // ---- Mode 1: header-based signing for programmatic / JSON / multipart callers ----
71	        String headerSig = request.getHeader("X-Signature");
72	        String headerTs = request.getHeader("X-Timestamp");
73	        if (headerSig != null && !headerSig.isBlank()) {
74	            if (headerTs == null || headerTs.isBlank()) {
75	                forbid(response, "Missing X-Timestamp header");
76	                return;
77	            }
78	            ContentCachingRequestWrapper wrapped = new ContentCachingRequestWrapper(request);
79	            // Force the chain to read the body before we sign it; we still pass `wrapped` down.
80	            wrapped.getInputStream().readAllBytes();
81	            byte[] body = wrapped.getContentAsByteArray();
82	            String bodyHashHex = sha256Hex(body);
83	
84	            String canonical = request.getMethod() + "\n"
85	                    + request.getRequestURI() + "\n"
86	                    + headerTs + "\n"
87	                    + bodyHashHex;
88	            String expected = hmacSha256Hex(canonical, signingSecret);
89	            if (!constantTimeEquals(expected, headerSig)) {
90	                log.warn("Request signature mismatch (header mode) on {}", request.getRequestURI());
91	                forbid(response, "Invalid request signature");
92	                return;
93	            }
94	            chain.doFilter(wrapped, response);
95	            return;
96	        }
97	
98	        // ---- Mode 2: form-parameter signing for browser POSTs ----
99	        // Browser forms are enriched by static/js/nonce-form.js with _nonce / _timestamp /
100	        // _signature hidden fields fetched from the server-side sign-form endpoint.
101	        String formSig = request.getParameter("_signature");
102	        String formTs = request.getParameter("_timestamp");
103	        String formNonce = request.getParameter("_nonce");
104	        if (formSig != null && !formSig.isBlank()) {
105	            if (formTs == null || formTs.isBlank() || formNonce == null || formNonce.isBlank()) {
106	                forbid(response, "Missing _timestamp or _nonce form parameter alongside _signature");
107	                return;
108	            }
109	            String canonical = request.getMethod() + "\n"
110	                    + request.getRequestURI() + "\n"
111	                    + formTs + "\n"
112	                    + formNonce;
113	            String expected = hmacSha256Hex(canonical, signingSecret);
114	            if (!constantTimeEquals(expected, formSig)) {
115	                log.warn("Request signature mismatch (form mode) on {}", request.getRequestURI());
116	                forbid(response, "Invalid request signature");
117	                return;
118	            }
119	            chain.doFilter(request, response);
120	            return;
121	        }
122	
123	        forbid(response, "Missing X-Signature header or _signature form parameter");
124	    }
125	
126	    /**
127	     * Compute the form-mode signature for a (method, path, timestamp, nonce) tuple.
128	     * Used by {@link com.meridian.retail.controller.NonceController} so the JS layer
129	     * can fetch a server-issued signature without ever holding the HMAC secret.
130	     */
131	    public String signFormCanonical(String method, String path, String timestamp, String nonce) {
132	        String canonical = method + "\n" + path + "\n" + timestamp + "\n" + nonce;
133	        return hmacSha256Hex(canonical, signingSecret);
134	    }
135	
136	    private boolean appliesTo(HttpServletRequest request) {
137	        if (!"POST".equalsIgnoreCase(request.getMethod())) return false;
138	        String uri = request.getRequestURI();
139	        // Sign-form endpoint issues the very signature this filter validates — exclude
140	        // it to avoid a chicken-and-egg loop. Spring Security role checks still gate it.
141	        if (uri.equals("/admin/sign-form")) return false;
142	        return uri.startsWith("/admin/");
143	    }
144	
145	    /**
146	     * R4 audit HIGH #2 fix: form-encoded bypass for /admin/** has been removed.
147	     * Browser forms now reach this filter and validate via form-mode (_signature
148	     * parameter, server-issued through {@code POST /admin/sign-form}). The override
149	     * therefore returns false — every request flows through doFilterInternal, which
150	     * applies its own method/URL filter via {@link #appliesTo(HttpServletRequest)}.
151	     */
152	    @Override
153	    protected boolean shouldNotFilter(HttpServletRequest request) {
154	        return false;
155	    }
156	
157	    private void forbid(HttpServletResponse response, String reason) throws IOException {
158	        response.setStatus(HttpServletResponse.SC_FORBIDDEN);
159	        response.setContentType("application/json");
160	        response.getWriter().write("{\"error\":\"" + reason + "\"}");
161	    }
162	
163	    private static String sha256Hex(byte[] data) {
164	        try {
165	            MessageDigest md = MessageDigest.getInstance("SHA-256");
166	            return HexFormat.of().formatHex(md.digest(data));
167	        } catch (Exception e) {
168	            throw new IllegalStateException("SHA-256 unavailable", e);
169	        }
170	    }
171	
172	    private static String hmacSha256Hex(String data, String key) {
173	        try {
174	            Mac mac = Mac.getInstance("HmacSHA256");
175	            mac.init(new SecretKeySpec(key.getBytes(StandardCharsets.UTF_8), "HmacSHA256"));
176	            return HexFormat.of().formatHex(mac.doFinal(data.getBytes(StandardCharsets.UTF_8)));
177	        } catch (Exception e) {
178	            throw new IllegalStateException("HMAC-SHA256 unavailable", e);
179	        }
180	    }
181	
182	    /** Constant-time comparison to avoid timing attacks. */
183	    private static boolean constantTimeEquals(String a, String b) {
184	        if (a == null || b == null || a.length() != b.length()) return false;
185	        int diff = 0;
186	        for (int i = 0; i < a.length(); i++) {
187	            diff |= a.charAt(i) ^ b.charAt(i);
188	        }
189	        return diff == 0;
190	    }
191	}
