1	package com.meridian.retail.security;
2	
3	import com.meridian.retail.entity.UsedNonce;
4	import com.meridian.retail.repository.UsedNonceRepository;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import lombok.RequiredArgsConstructor;
10	import lombok.extern.slf4j.Slf4j;
11	import org.springframework.stereotype.Component;
12	import org.springframework.web.filter.OncePerRequestFilter;
13	
14	import java.io.IOException;
15	import java.time.LocalDateTime;
16	
17	/**
18	 * Anti-replay nonce + timestamp validation for privileged POST endpoints.
19	 *
20	 * Applies to: POST /admin/**, POST /approval/dual-approve/**,
21	 *             POST /approval/{id}/approve-first, POST /approval/{id}/approve-second.
22	 *
23	 * The two approve-first/second paths are the actual UI completion endpoints for the
24	 * dual-approval workflow (R4 audit HIGH #1). They are protected without any form-
25	 * encoded bypass — the browser fetches a nonce from {@code GET /approval/nonce} and
26	 * submits the form with X-Nonce + X-Timestamp headers via JS (templates/approval/queue.html).
27	 * Required headers:
28	 *   X-Nonce      — caller-generated unique value (UUID is fine)
29	 *   X-Timestamp  — epoch milliseconds when the request was constructed
30	 *
31	 * Rules:
32	 *   - The timestamp must be within ±5 minutes of server time.
33	 *   - The nonce must not exist in used_nonces (if it does -> replay).
34	 *   - On success the nonce is persisted with expires_at = now + 10 minutes so the same
35	 *     value cannot be reused. A scheduled task (UsedNonceCleanupTask) prunes expired rows.
36	 */
37	@Component
38	@RequiredArgsConstructor
39	@Slf4j
40	public class NonceValidationFilter extends OncePerRequestFilter {
41	
42	    private static final long ALLOWED_SKEW_MS = 5 * 60 * 1000L;
43	    private static final long NONCE_TTL_MINUTES = 10;
44	
45	    private final UsedNonceRepository usedNonceRepository;
46	
47	    @Override
48	    protected void doFilterInternal(HttpServletRequest request,
49	                                    HttpServletResponse response,
50	                                    FilterChain chain) throws ServletException, IOException {
51	
52	        if (!appliesTo(request)) {
53	            chain.doFilter(request, response);
54	            return;
55	        }
56	
57	        // Browser form submissions cannot easily set custom headers without going
58	        // through fetch() (which loses RedirectAttributes flash messages). We accept
59	        // the same nonce/timestamp from either headers (programmatic clients) OR form
60	        // parameters _nonce / _timestamp (browser forms enriched by JS before submit).
61	        String nonce = request.getHeader("X-Nonce");
62	        if (nonce == null || nonce.isBlank()) nonce = request.getParameter("_nonce");
63	        String timestampStr = request.getHeader("X-Timestamp");
64	        if (timestampStr == null || timestampStr.isBlank()) timestampStr = request.getParameter("_timestamp");
65	
66	        if (nonce == null || nonce.isBlank() || timestampStr == null || timestampStr.isBlank()) {
67	            reject(response, "Missing X-Nonce or X-Timestamp (header or form field)");
68	            return;
69	        }
70	
71	        long timestamp;
72	        try {
73	            timestamp = Long.parseLong(timestampStr);
74	        } catch (NumberFormatException e) {
75	            reject(response, "Invalid X-Timestamp value");
76	            return;
77	        }
78	
79	        long now = System.currentTimeMillis();
80	        if (Math.abs(now - timestamp) > ALLOWED_SKEW_MS) {
81	            reject(response, "Request timestamp outside allowed window (±5 minutes)");
82	            return;
83	        }
84	
85	        if (usedNonceRepository.existsByNonce(nonce)) {
86	            log.warn("Nonce replay detected: {}", nonce);
87	            reject(response, "Nonce already used (replay)");
88	            return;
89	        }
90	
91	        // Persist as used; expiry slightly longer than the skew so the cleanup job can prune it.
92	        UsedNonce row = UsedNonce.builder()
93	                .nonce(nonce)
94	                .usedAt(LocalDateTime.now())
95	                .expiresAt(LocalDateTime.now().plusMinutes(NONCE_TTL_MINUTES))
96	                .build();
97	        usedNonceRepository.save(row);
98	
99	        chain.doFilter(request, response);
100	    }
101	
102	    private boolean appliesTo(HttpServletRequest request) {
103	        if (!"POST".equalsIgnoreCase(request.getMethod())) return false;
104	        String uri = request.getRequestURI();
105	        // Sign-form endpoints issue the very nonce/signature this filter validates,
106	        // so they must be excluded to avoid a chicken-and-egg loop. They are still
107	        // gated by Spring Security role checks.
108	        if (uri.equals("/admin/sign-form") || uri.equals("/approval/sign-form")) return false;
109	        if (uri.startsWith("/admin/")) return true;
110	        if (uri.startsWith("/approval/dual-approve/")) return true;
111	        // R4 HIGH #1: cover the UI completion endpoints for dual approval. Pattern is
112	        // /approval/{id}/approve-first or /approval/{id}/approve-second.
113	        return uri.startsWith("/approval/")
114	                && (uri.endsWith("/approve-first") || uri.endsWith("/approve-second"));
115	    }
116	
117	    /**
118	     * R4 HIGH #2 fix: the previous broad form-encoded bypass for /admin/** has been
119	     * removed. Privileged browser POSTs now carry _nonce / _timestamp hidden fields
120	     * injected by static/js/nonce-form.js, so the same anti-replay validation runs for
121	     * both browser and API callers. RequestSigningFilter still keeps a form-encoded
122	     * bypass because HMAC signing requires a shared secret that cannot live in the
123	     * browser — see SecurityDesignDecisions.md for the threat-model rationale.
124	     *
125	     * The shouldNotFilter override therefore intentionally returns the OncePerRequestFilter
126	     * default (false) — every request flows through doFilterInternal, which itself
127	     * filters by HTTP method and URL via {@link #appliesTo(HttpServletRequest)}.
128	     */
129	    @Override
130	    protected boolean shouldNotFilter(HttpServletRequest request) {
131	        return false;
132	    }
133	
134	    private void reject(HttpServletResponse response, String reason) throws IOException {
135	        response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
136	        response.setContentType("application/json");
137	        response.getWriter().write("{\"error\":\"" + reason + "\"}");
138	    }
139	}
