1	package com.meridian.retail.controller;
2	
3	import com.meridian.retail.security.RequestSigningFilter;
4	import lombok.RequiredArgsConstructor;
5	import org.springframework.security.access.prepost.PreAuthorize;
6	import org.springframework.web.bind.annotation.GetMapping;
7	import org.springframework.web.bind.annotation.PostMapping;
8	import org.springframework.web.bind.annotation.RequestBody;
9	import org.springframework.web.bind.annotation.RestController;
10	
11	import java.util.Map;
12	import java.util.UUID;
13	
14	/**
15	 * Issues anti-replay nonces for browser-driven privileged form submissions.
16	 *
17	 * The nonce is a single-use opaque UUID; the timestamp is server epoch milliseconds so
18	 * the client does not need a synchronized clock. The browser includes both as
19	 * {@code X-Nonce} and {@code X-Timestamp} headers on its subsequent privileged POST,
20	 * where {@link com.meridian.retail.security.NonceValidationFilter} validates the
21	 * timestamp window and persists the nonce to the {@code used_nonces} table.
22	 *
23	 * Why this is safe to expose without signing: nonces are single-use by construction
24	 * and are themselves stored on the server side. An attacker who scrapes one cannot
25	 * reuse it on a different request, and an authenticated session is still required to
26	 * reach this endpoint.
