35	    @PreAuthorize("hasAnyRole('ADMIN','REVIEWER')")
36	    public Map<String, Object> approvalNonce() {
37	        return Map.of(
38	                "nonce", UUID.randomUUID().toString(),
39	                "timestamp", System.currentTimeMillis()
40	        );
41	    }
42	
43	    @GetMapping("/admin/nonce")
44	    @PreAuthorize("hasRole('ADMIN')")
45	    public Map<String, Object> adminNonce() {
46	        return Map.of(
47	                "nonce", UUID.randomUUID().toString(),
48	                "timestamp", System.currentTimeMillis()
49	        );
50	    }
51	
52	    /**
53	     * Server-side HMAC signing for browser POSTs. R4 audit HIGH #2 fix: by routing the
54	     * signing through this endpoint we can keep the HMAC secret on the server while
55	     * still attaching a valid {@code _signature} form parameter to every privileged
