75	    @PreAuthorize("hasAnyRole('ADMIN','REVIEWER')")
76	    public Map<String, Object> signApprovalForm(@RequestBody Map<String, String> req) {
77	        return Map.of("signature", sign(req));
78	    }
79	
80	    private String sign(Map<String, String> req) {
81	        String method = req.getOrDefault("method", "POST");
82	        String path = req.get("path");
83	        String timestamp = req.get("timestamp");
84	        String nonce = req.get("nonce");
85	        if (path == null || timestamp == null || nonce == null) {
86	            throw new IllegalArgumentException("path, timestamp, and nonce are required");
87	        }
