9	/**
10	 * Base class for all integration tests.
11	 *
12	 * Two modes:
13	 *   1. LOCAL DEV — Testcontainers spins up a fresh MySQL 8 container per JVM run (started
14	 *      lazily in {@link #registerProps}).
15	 *   2. INSIDE docker-compose.test.yml — the {@code mysql-test} service is already running on
16	 *      the same docker network. We detect this via the IT_DATASOURCE_URL environment variable
17	 *      and skip Testcontainers entirely (Testcontainers' "host.docker.internal" port mapping
18	 *      cannot reach a docker-spawned container from inside another container).
19	 *
20	 * In either mode Flyway runs the real migrations and {@code ddl-auto} is forced to "validate".
21	 *
22	 * Note: We deliberately do NOT use {@code @Testcontainers} / {@code @Container} annotations
23	 * because they require an always-non-null container field, which prevents the conditional
24	 * external-DB mode.
25	 */
26	@SpringBootTest
27	@ActiveProfiles("test")
28	public abstract class AbstractIntegrationTest {
29	
30	    private static final String EXTERNAL_URL = System.getenv("IT_DATASOURCE_URL");
31	    private static final boolean USE_EXTERNAL = EXTERNAL_URL != null && !EXTERNAL_URL.isBlank();
32	
33	    private static MySQLContainer<?> MYSQL;
34	
35	    @DynamicPropertySource
36	    static void registerProps(DynamicPropertyRegistry r) {
37	        if (USE_EXTERNAL) {
38	            // Inside docker-compose.test.yml — connect to the sibling mysql-test service.
39	            r.add("spring.datasource.url", () -> EXTERNAL_URL);
40	            r.add("spring.datasource.username",
41	                    () -> System.getenv().getOrDefault("IT_DATASOURCE_USERNAME", "retail_user"));
42	            r.add("spring.datasource.password",
43	                    () -> System.getenv().getOrDefault("IT_DATASOURCE_PASSWORD", "retail_pass"));
44	        } else {
45	            // Local dev — lazily start a single MySQL container shared across the whole JVM.
46	            if (MYSQL == null) {
47	                MYSQL = new MySQLContainer<>("mysql:8.0")
48	                        .withDatabaseName("retail_campaign_test")
49	                        .withUsername("retail_user")
50	                        .withPassword("retail_pass")
51	                        // V14 installs immutability triggers. With binary logging enabled
52	                        // (MySQL 8 default) a non-SUPER user can't create triggers unless
53	                        // log_bin_trust_function_creators=ON.
54	                        .withCommand("--log-bin-trust-function-creators=ON");
55	                MYSQL.start();
56	                Runtime.getRuntime().addShutdownHook(new Thread(MYSQL::stop));
57	            }
58	            r.add("spring.datasource.url", MYSQL::getJdbcUrl);
59	            r.add("spring.datasource.username", MYSQL::getUsername);
60	            r.add("spring.datasource.password", MYSQL::getPassword);
61	        }
