2	 * Browser anti-replay nonce + signature injection.
3	 *
4	 * R4 audit HIGH #1 + HIGH #2: NonceValidationFilter and RequestSigningFilter no longer
5	 * carry blanket bypasses for browser POSTs. Privileged browser submissions must therefore
6	 * carry both a fresh nonce/timestamp AND a server-issued HMAC signature. Rather than
7	 * rewriting every admin form to be HTMX/fetch-driven (which would lose Spring's
8	 * RedirectAttributes flash messages), this script intercepts the form submit, fetches a
9	 * nonce from the appropriate /admin/nonce or /approval/nonce endpoint, fetches a
10	 * signature from /admin/sign-form (admin paths only — RequestSigningFilter is scoped to
11	 * /admin/**), injects _nonce / _timestamp / _signature as hidden fields, and lets the
12	 * browser perform a normal POST.
13	 *
14	 * Why server-side signing? HMAC-SHA256 needs the shared signing secret which can never
15	 * live in browser JavaScript. The /admin/sign-form endpoint is gated by Spring Security
16	 * (ROLE_ADMIN + authenticated session + CSRF), so an unauthorized caller cannot obtain a
17	 * signature. The signature binds (method, path, timestamp, nonce); the body hash is
18	 * intentionally omitted because the body itself contains _signature (chicken-and-egg).
19	 * Replay protection comes from the single-use nonce that NonceValidationFilter consumes.
20	 *
21	 * Behaviour:
22	 *   - Auto-arms any <form method="post"> whose action is under /admin/ or
23	 *     /approval/{id}/approve-first|second|/dual-approve/.
24	 *   - For /admin/** forms: fetches both nonce and signature.
25	 *   - For /approval/** forms: fetches nonce only (signing filter is /admin/**-scoped).
26	 *   - Skips forms tagged data-skip-nonce="true".
27	 *   - Skips submit buttons tagged data-skip-nonce="true" (e.g. Reject buttons that don't
28	 *     change campaign state to APPROVED — they fall through to a normal POST).
29	 *   - Skips logout (handled by Spring Security separately).
30	 */
31	(function () {
32	    var CSRF_TOKEN = (function () {
33	        var meta = document.querySelector('meta[name="_csrf"]');
34	        return meta ? meta.getAttribute('content') : '';
35	    })();
36	    var CSRF_HEADER = (function () {
37	        var meta = document.querySelector('meta[name="_csrf_header"]');
38	        return meta ? meta.getAttribute('content') : 'X-XSRF-TOKEN';
39	    })();
40	
41	    function nonceEndpointFor(action) {
42	        if (action.indexOf('/admin/') === 0) return '/admin/nonce';
43	        if (action.indexOf('/approval/') === 0) return '/approval/nonce';
44	        return null;
45	    }
46	
47	    function signEndpointFor(action) {
48	        // RequestSigningFilter is scoped to /admin/**, so signing is required only there.
49	        if (action.indexOf('/admin/') === 0) return '/admin/sign-form';
50	        return null;
51	    }
52	
53	    function needsNonce(form) {
54	        if (form.method && form.method.toLowerCase() !== 'post') return false;
55	        if (form.dataset.skipNonce === 'true') return false;
56	        var action = form.getAttribute('action') || window.location.pathname;
57	        if (action.indexOf('/logout') === 0) return false;
58	        if (action.indexOf('/admin/') === 0) return true;
59	        if (action.indexOf('/approval/') === 0
60	                && (action.indexOf('/approve-first') !== -1
61	                    || action.indexOf('/approve-second') !== -1
62	                    || action.indexOf('/dual-approve/') !== -1)) {
63	            return true;
64	        }
65	        return false;
66	    }
67	
68	    function fetchNonce(endpoint) {
69	        return fetch(endpoint, {
70	            method: 'GET',
71	            credentials: 'same-origin',
72	            headers: { 'Accept': 'application/json' }
73	        }).then(function (r) {
74	            if (!r.ok) throw new Error('nonce fetch failed: ' + r.status);
75	            return r.json();
76	        });
77	    }
78	
79	    function fetchSignature(endpoint, method, path, timestamp, nonce) {
80	        var headers = { 'Content-Type': 'application/json', 'Accept': 'application/json' };
81	        if (CSRF_TOKEN) headers[CSRF_HEADER] = CSRF_TOKEN;
82	        return fetch(endpoint, {
83	            method: 'POST',
84	            credentials: 'same-origin',
85	            headers: headers,
86	            body: JSON.stringify({
87	                method: method,
88	                path: path,
89	                timestamp: String(timestamp),
90	                nonce: nonce
91	            })
92	        }).then(function (r) {
93	            if (!r.ok) throw new Error('signature fetch failed: ' + r.status);
94	            return r.json();
95	        });
96	    }
97	
98	    function setHidden(form, name, value) {
99	        var input = form.querySelector('input[type=hidden][name="' + name + '"]');
100	        if (!input) {
101	            input = document.createElement('input');
102	            input.type = 'hidden';
103	            input.name = name;
104	            form.appendChild(input);
105	        }
106	        input.value = value;
107	    }
108	
109	    function arm(form) {
110	        if (form.dataset.nonceWired === 'true') return;
111	        form.dataset.nonceWired = 'true';
112	
113	        var lastSubmitter = null;
114	        form.querySelectorAll('button[type=submit], input[type=submit]').forEach(function (btn) {
115	            btn.addEventListener('click', function () { lastSubmitter = btn; });
116	        });
117	
118	        form.addEventListener('submit', function (ev) {
119	            if (lastSubmitter && lastSubmitter.getAttribute('data-skip-nonce') === 'true') {
120	                return;
121	            }
122	            // Use the button's formaction (if set) over the form action so Reject /
123	            // alternative submit buttons get scoped correctly.
124	            var action = (lastSubmitter && lastSubmitter.getAttribute('formaction'))
125	                    || form.getAttribute('action')
126	                    || window.location.pathname;
127	            if (form.dataset.nonceArmed === 'true') return;
128	
129	            var nonceEndpoint = nonceEndpointFor(action);
130	            if (!nonceEndpoint) return; // not a privileged path — let the browser submit normally
131	            var signEndpoint = signEndpointFor(action);
132	
133	            ev.preventDefault();
134	
135	            fetchNonce(nonceEndpoint).then(function (n) {
136	                // Inject nonce + timestamp first; if we don't need a signature we can
137	                // submit immediately.
138	                setHidden(form, '_nonce', n.nonce);
139	                setHidden(form, '_timestamp', String(n.timestamp));
140	                if (!signEndpoint) {
141	                    return null; // signal "skip signing"
142	                }
143	                return fetchSignature(signEndpoint, 'POST', action, n.timestamp, n.nonce);
144	            }).then(function (sigResp) {
145	                if (sigResp && sigResp.signature) {
146	                    setHidden(form, '_signature', sigResp.signature);
147	                }
148	                form.dataset.nonceArmed = 'true';
149	                if (lastSubmitter) {
150	                    lastSubmitter.click();
151	                } else {
152	                    form.submit();
153	                }
154	            }).catch(function (err) {
155	                alert('Could not arm privileged form: ' + err.message);
156	            });
157	        });
158	    }
159	
160	    function scan(root) {
161	        (root || document).querySelectorAll('form').forEach(function (form) {
162	            if (needsNonce(form)) arm(form);
163	        });
164	    }
165	
166	    if (document.readyState === 'loading') {
167	        document.addEventListener('DOMContentLoaded', function () { scan(document); });
168	    } else {
169	        scan(document);
170	    }
171	})();
